use serde::Serialize;
use std::collections::HashSet;

#[derive(Debug, Clone)]
pub struct FunctionInfo {
    pub file: String,
    pub start_line: usize,
    pub end_line: usize,
    pub node_hashes: Vec<u64>,
}

#[derive(Debug, Clone, Serialize)]
pub struct PairEndpoint {
    pub file: String,
    pub start_line: usize,
    pub end_line: usize,
    pub nodes: usize,
}

#[derive(Debug, Clone, Serialize)]
pub struct DuplicatePair {
    pub score: f64,
    pub left: PairEndpoint,
    pub right: PairEndpoint,
}

pub struct Config {
    pub threshold: f64,
    pub min_lines: usize,
    pub min_nodes: usize,
    pub format: OutputFormat,
    pub excludes: Vec<String>,
}

impl Default for Config {
    fn default() -> Self {
        Config {
            threshold: 0.82,
            min_lines: 4,
            min_nodes: 20,
            format: OutputFormat::Text,
            excludes: vec![],
        }
    }
}

pub enum OutputFormat {
    Text,
    Json,
}

pub enum RunResult {
    Clean,
    Duplicates(Vec<DuplicatePair>),
    Error(String),
}

pub fn parse_output_format(s: &str) -> Result<OutputFormat, String> {
    match s {
        "json" => Ok(OutputFormat::Json),
        "text" => Ok(OutputFormat::Text),
        other => Err(format!("unknown format '{}'; use 'text' or 'json'", other)),
    }
}

pub fn validate_lang(lang: &str) -> Result<(), String> {
    if lang == "rust" {
        Ok(())
    } else {
        Err(format!(
            "unsupported language '{}'; only 'rust' is supported",
            lang
        ))
    }
}

