118	pub fn find_duplicate_pairs(
119	    functions: &[FunctionInfo],
120	    threshold: f64,
121	    min_lines: usize,
122	    min_nodes: usize,
123	) -> Vec<DuplicatePair> {
124	    let candidates: Vec<&FunctionInfo> = functions
125	        .iter()
126	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
127	        .collect();
128	
129	    let mut pairs: Vec<DuplicatePair> = Vec::new();
130	
131	    for i in 0..candidates.len() {
132	        for j in (i + 1)..candidates.len() {
133	            let a = candidates[i];
134	            let b = candidates[j];
135	            if is_same_location(a, b) {
136	                continue;
137	            }
138	            let score = jaccard(&a.node_hashes, &b.node_hashes);
139	            if score >= threshold {
140	                pairs.push(make_pair(a, b, score));
141	            }
142	        }
143	    }
144	
145	    pairs.sort_by(|a, b| {
146	        b.score
147	            .partial_cmp(&a.score)
148	            .unwrap_or(std::cmp::Ordering::Equal)
149	            .then_with(|| a.left.file.cmp(&b.left.file))
150	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
151	            .then_with(|| a.right.file.cmp(&b.right.file))
152	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
153	    });
154	
155	    pairs
156	}
