158	fn order_endpoints<'a>(
159	    a: &'a FunctionInfo,
160	    b: &'a FunctionInfo,
161	) -> (&'a FunctionInfo, &'a FunctionInfo) {
162	    let cmp = a
163	        .file
164	        .cmp(&b.file)
165	        .then_with(|| a.start_line.cmp(&b.start_line));
166	    if cmp == std::cmp::Ordering::Greater {
167	        (b, a)
168	    } else {
169	        (a, b)
170	    }
171	}
