240	    format_str: &str,
241	    lang: Option<&str>,
242	    config: Config,
243	    run_fn: impl Fn(&[String], &Config) -> RunResult,
244	) -> CliResult {
245	    let format = match parse_output_format(format_str) {
246	        Ok(f) => f,
247	        Err(e) => return cli_error(e),
